/*
 * @Author: Generated by Copilot
 * @Date: 2025-11-03
 * @Description: 小红书用户主页 Drawer：展示用户头像/昵称及其已发布笔记瀑布流，可翻页加载。
 */
import React, { useCallback, useEffect, useRef, useState } from "react";
import { Empty } from "antd";
import Masonry from "react-masonry-css";
import InfiniteScroll from "react-infinite-scroll-component";
import { createXhsApi } from "../api";
import { useRequest } from "../hooks/useRequest";
import { useFollowUser } from "../hooks/useFollowUser";
import XhsFeedCard from "./XhsFeedCard";
import { loaderFunc } from "../utils/loader";
import BaseDrawer from "./BaseDrawer";
import UserInfoCard from "./UserInfoCard";
import FeedDetailDrawer from "./FeedDetailDrawer";
import { XhsFeedRawItem } from "../../../types/xhs";
import { INFINITE_SCROLL_CONFIG } from "../constants";

interface UserPostedDrawerProps {
  open: boolean;
  onClose: () => void;
  // 初始参数：从点击的笔记中获取 note id 作为 cursor（或空字符串），以及 user 对象里的 user_id 与 xsec_token
  initParams: {
    xsec_source?: any;
    user_id: string;
    cursor: string;
    xsec_token?: string;
    user?: any;
  };
}

const UserPostedDrawer: React.FC<UserPostedDrawerProps> = ({
  open,
  onClose,
  initParams,
}) => {
  const { request, messageApi } = useRequest();
  const apiRef = useRef(createXhsApi(request));

  const [loading, setLoading] = useState(false);
  const [cursor, setCursor] = useState(initParams.cursor);
  const [items, setItems] = useState<XhsFeedRawItem[]>([]);
  const [hasMore, setHasMore] = useState(true);
  // 使用 ref 保存最新 cursor，避免将 cursor 纳入 useCallback 依赖导致函数重建和二次请求
  const cursorRef = useRef(cursor);

  // 内部 FeedDetailDrawer 状态
  const [detailOpen, setDetailOpen] = useState(false);
  const [selectedNote, setSelectedNote] = useState<any>(null);

  const handleOpenDetail = (raw: any) => {
    setSelectedNote(raw);
    setDetailOpen(true);
  };

  // 用户信息基础展示（初始）
  const user = initParams.user || {}; // 兼容从 note_card.user 传入
  const nickname: string = user.nick_name || user.nickname || "未知用户";

  // Hover Card 详细数据
  const [hoverLoading, setHoverLoading] = useState(false);
  const [hoverError, setHoverError] = useState<string | null>(null);
  const [hoverData, setHoverData] = useState<any>(null);

  const fetchHover = useCallback(async () => {
    if (!initParams.user_id) return;
    setHoverLoading(true);
    setHoverError(null);
    setHoverData(null);
    try {
      const res: any = await apiRef.current.getUserHoverCard({
        target_user_id: initParams.user_id,
        image_formats: "jpg,webp,avif",
        xsec_source: "pc_comment",
        xsec_token: initParams.xsec_token || "",
      });
      // 兼容后端直接返回 data 或完整响应
      const dataLayer = res?.basic_info ? res : res?.data;
      setHoverData(dataLayer || null);
    } catch (e: any) {
      setHoverError(e?.message || "用户信息加载失败");
    } finally {
      setHoverLoading(false);
    }
  }, [initParams.user_id, initParams.xsec_token]);

  const fetchPosted = useCallback(
    async (reset: boolean = false, nextCursor?: string) => {
      if (!initParams.user_id) return;
      const useCursor = reset
        ? nextCursor ?? ""
        : nextCursor ?? cursorRef.current;
      setLoading(true);
      try {
        const res: any = await apiRef.current.getUserPosted({
          user_id: initParams.user_id,
          cursor: useCursor,
          xsec_token: initParams.xsec_token || "",
          xsec_source: initParams.xsec_source,
        });
        const incoming: XhsFeedRawItem[] = res?.items || [];
        setItems((prev) => (reset ? incoming : [...prev, ...incoming]));
        const newCursor = res?.cursor || "";
        setCursor(newCursor);
        cursorRef.current = newCursor; // 同步 ref
        setHasMore(!!res?.has_more);
      } catch (e) {
        console.error("[xhs user posted] error", e);
      } finally {
        setLoading(false);
      }
    },
    [initParams.user_id, initParams.xsec_source, initParams.xsec_token]
  );

  const loadMore = useCallback(() => {
    if (!hasMore || loading) return;
    fetchPosted(false, cursorRef.current);
  }, [fetchPosted, hasMore, loading]);

  useEffect(() => {
    if (open) {
      const firstCursor = initParams.cursor || "";
      setItems([]);
      setCursor(firstCursor);
      cursorRef.current = firstCursor;
      setHasMore(true);
      fetchPosted(true, firstCursor);
      fetchHover();
    } else {
      setItems([]);
      setCursor("");
      cursorRef.current = "";
      setHasMore(true);
      setHoverData(null);
      setHoverError(null);
    }
    // 仅在 open 或 initParams 关键字段变化时触发，不添加 fetchPosted 以避免重复请求
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [open, initParams.cursor, initParams.user_id]);

  const isFollowed =
    hoverData?.extraInfo_info?.fstatus &&
    hoverData.extraInfo_info.fstatus !== "none";

  // 使用统一的关注 Hook
  const { toggleFollow, loading: followLoading } = useFollowUser({
    initialFollowing: isFollowed,
    onSuccess: (newFollowingState) => {
      // 成功后更新 hover data 中的关注状态
      setHoverData((prev: any) => ({
        ...prev,
        extraInfo_info: {
          ...(prev?.extraInfo_info || {}),
          fstatus: newFollowingState ? "follows" : "none",
        },
      }));
    },
    onError: () => {
      // 失败后重新拉取 hover card 以恢复真实状态
      fetchHover();
    },
  });

  const handleFollowClick = async () => {
    if (!initParams.user_id) return;
    await toggleFollow(initParams.user_id);
  };

  return (
    <>
      <BaseDrawer
        open={open}
        onClose={onClose}
        title={`用户主页 - ${nickname}`}
        scrollableId="xhsUserScrollableDiv"
      >
        {/* 用户详情区（统一组件） */}
        <UserInfoCard
          user={user}
          hoverData={hoverData}
          loading={hoverLoading}
          error={hoverError}
          mode="detailed"
          showFollowButton={!!initParams.user_id}
          isFollowing={isFollowed}
          followLoading={followLoading}
          onFollowToggle={handleFollowClick}
        />

        {/* 瀑布流 */}
        {loading && items.length === 0 ? (
          <div style={{ padding: "20px 0" }}>{loaderFunc()}</div>
        ) : items.length > 0 ? (
          <InfiniteScroll
            dataLength={items.length}
            next={loadMore}
            hasMore={hasMore && !loading}
            loader={loaderFunc()}
            endMessage={
              <div style={{ padding: 8, textAlign: "center", color: "#999" }}>
                没有更多了
              </div>
            }
            scrollableTarget="xhsUserScrollableDiv"
            scrollThreshold={INFINITE_SCROLL_CONFIG.THRESHOLD}
          >
            <Masonry
              breakpointCols={{
                default: 2,
                1500: 5,
                1200: 4,
                900: 3,
                600: 2,
                300: 1,
              }}
              className="xhs-masonry"
              columnClassName="xhs-masonry-column"
            >
              {items.map((raw: any, index: number) => (
                <div
                  key={raw.id + index}
                  className="xhs-waterfall-item"
                  style={{ animationDelay: `${(index % 10) * 50}ms` }}
                >
                  <XhsFeedCard
                    data={raw}
                    onClick={() => handleOpenDetail(raw)}
                    onUserClick={() => {
                      // 已在当前用户主页
                      messageApi.info("已经是本用户主页了");
                    }}
                  />
                </div>
              ))}
            </Masonry>
          </InfiniteScroll>
        ) : (
          <Empty
            description="暂无用户笔记"
            image={Empty.PRESENTED_IMAGE_SIMPLE}
          />
        )}
        {/* 在 UserPostedDrawer 内部嵌套打开 FeedDetailDrawer */}
        {selectedNote && (
          <FeedDetailDrawer
            open={detailOpen}
            onClose={() => setDetailOpen(false)}
            detail={{
              note_id: selectedNote.id || selectedNote.note_id,
              xsec_token: selectedNote.xsec_token,
            }}
          />
        )}
      </BaseDrawer>
    </>
  );
};

export default UserPostedDrawer;
